// Validate & normalize
const body = $json.body || $json;
const required = ["orderId","origin","destination","weight","serviceType"];
const missing = required.filter(k => body[k] == null || body[k] === "");
if (missing.length) throw new Error("Missing: " + missing.join(", "));
return {
  orderId: body.orderId,
  customerId: body.customerId || null,
  origin: body.origin,
  destination: body.destination,
  weight: Number(body.weight),
  serviceType: String(body.serviceType).toLowerCase(),
  notes: body.notes || ""
};

// Select Vehicle (n8n Code node)

const vehicles = $input.all().map((item) => item.json);
if (!vehicles.length) {
  throw new Error("No vehicles returned from Get driver info.");
}

const normalizeText = (value) =>
  String(value || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");

const order = $items("Validate Order Intake")[0]?.json || {};
const aiParse = $items("Parse output")[0]?.json || {};

const origin = order.origin || "";
const originNorm = normalizeText(origin);

const targetVehicleType = aiParse.vehicle_type
  ? String(aiParse.vehicle_type).toLowerCase()
  : null;

const candidates = vehicles.filter((vehicle) => {
  const statusOk = String(vehicle.status || "").toLowerCase() === "available";
  const typeOk = targetVehicleType
    ? String(vehicle.vehicle_type || "").toLowerCase() === targetVehicleType
    : false;

  const regionNorm = normalizeText(vehicle.region || "");
  const regionOk = originNorm && regionNorm.includes(originNorm);

  return statusOk && typeOk && regionOk;
});

const selected = candidates[0] || null;

return selected
  ? {
      ...order,
      assignedVehicle: selected,
      assignedVehicleId: selected.id,
      vehicleType: selected.vehicle_type || null,
    }
  : {
      ...order,
      assignedVehicle: null,
      assignedVehicleId: null,
      vehicleType: targetVehicleType,
    };

// Assign Driver (n8n Code node)

const drivers = $input.all().map((item) => item.json);
if (!drivers.length) {
  throw new Error("No drivers returned from Get driver info.");
}

const normalizeText = (value) =>
  String(value || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");

const order = $items("Validate Order Intake")[0]?.json || {};
const origin = order.origin || "";
const originNorm = normalizeText(origin);

// 1) Basic filters
const available = drivers.filter((driver) => {
  const statusOk = String(driver.status || "").toLowerCase() === "available";
  const workload = Number(driver.workload ?? 0);
  return statusOk && workload < 6;
});

// 2) Region match (origin ~ region)
const regionMatches = available.filter((driver) => {
  const regionNorm = normalizeText(driver.region || "");
  return originNorm && (regionNorm.includes(originNorm) || originNorm.includes(regionNorm));
});

// 3) Pick candidates: prefer region match, else all available
const candidates = regionMatches.length ? regionMatches : available;

// 4) Pick lowest workload set
const minWorkload = Math.min(
  ...candidates.map((d) => Number(d.workload ?? 0))
);
const lowest = candidates.filter(
  (d) => Number(d.workload ?? 0) === minWorkload
);

// 5) Random pick among lowest workload
const selected =
  lowest.length > 1
    ? lowest[Math.floor(Math.random() * lowest.length)]
    : lowest[0] || null;

return selected
  ? {
      ...order,
      assignedDriver: selected,
      assignedDriverId: selected.id,
      assignedDriverName: selected.name || null,
      assignedDriverRegion: selected.region || null,
    }
  : {
      ...order,
      assignedDriver: null,
      assignedDriverId: null,
      assignedDriverName: null,
      assignedDriverRegion: null,
    };

const raw = $json.data ? JSON.parse($json.data) : $json;

const feature = raw.features?.[0];
const segment = feature?.properties?.segments?.[0];
const summary = feature?.properties?.summary;

const distanceMeters =
  summary?.distance ||
  segment?.distance ||
  0;

const durationSeconds =
  summary?.duration ||
  segment?.duration ||
  0;

return [
  {
    json: {
      distanceMeters,
      distanceKm: Number((distanceMeters / 1000).toFixed(1)),

      durationSeconds,
      durationMinutes: Number((durationSeconds / 60).toFixed(1)),
      durationHours: Number((durationSeconds / 3600).toFixed(2)),

      routeSummary: {
        distanceKm: Number((distanceMeters / 1000).toFixed(1)),
        durationHours: Number((durationSeconds / 3600).toFixed(2)),
      }
    }
  } 
  ]

// LTL/FTL classification & consolidation
const MIN_FILL_RATIO = 0.8;

const VEHICLE_CAPACITY = [
  { vehicleType: 'motorbike', capacityKg: 50 },
  { vehicleType: 'van', capacityKg: 1000 },
  { vehicleType: 'refrigerated_truck', capacityKg: 3500 },
  { vehicleType: 'heavy_truck', capacityKg: 15000 }
];

function getProvince(address) {
  const parts = String(address || '')
    .split(',')
    .map((part) => part.trim())
    .filter(Boolean);
  return parts.length ? parts[parts.length - 1] : String(address || '').trim();
}

function normalizeOrder(item) {
  const data = item.json || {};
  const orderId = data.id || data.orderId || '';
  const serviceType = String(data.service_type || data.serviceType || '').toLowerCase();
  const weightKg = Number(data.weight_kg ?? data.weight ?? 0) || 0;

  return {
    raw: data,
    orderId,
    serviceType,
    origin: data.origin || '',
    destination: data.destination || '',
    weightKg,
  };
}

function pickMinVehicle(weightKg) {
  if (!Number.isFinite(weightKg)) weightKg = 0;
  const sorted = [...VEHICLE_CAPACITY].sort((a, b) => a.capacityKg - b.capacityKg);
  return sorted.find((v) => v.capacityKg >= weightKg) || sorted[sorted.length - 1];
}

function pickLtlVehicle(weightKg, minFillRatio) {
  const sorted = [...VEHICLE_CAPACITY].sort((a, b) => a.capacityKg - b.capacityKg);

  const candidates = sorted.filter(
    (v) =>
      weightKg <= v.capacityKg &&
      weightKg / v.capacityKg >= minFillRatio
  );

  const selected = candidates[0] || pickMinVehicle(weightKg);

  const fillPercent =
    selected.capacityKg > 0
      ? (weightKg / selected.capacityKg) * 100
      : 0;

  const ready =
    weightKg >= selected.capacityKg * minFillRatio;

  return {
    ...selected,
    fillPercent: Number(fillPercent.toFixed(1)),
    ready
  };
}

const orders = $input
  .all()
  .map(normalizeOrder)
  .filter((o) => o.orderId);

if (orders.length === 0) {
  return [];
}

const ltlGroups = new Map();

for (const order of orders) {
  if (order.serviceType !== 'ltl') continue;

  const originProvince = getProvince(order.origin);
  const destinationProvince = getProvince(order.destination);

  const key = `${originProvince}__${destinationProvince}`;

  const group = ltlGroups.get(key) || {
    key,
    originProvince,
    destinationProvince,
    orders: [],
    totalWeightKg: 0,
  };

  group.orders.push(order);
  group.totalWeightKg += order.weightKg;

  ltlGroups.set(key, group);
}

const ltlPlans = new Map();

for (const group of ltlGroups.values()) {
  const vehicle = pickLtlVehicle(
    group.totalWeightKg,
    MIN_FILL_RATIO
  );

  ltlPlans.set(group.key, {
    ...group,
    vehicle,
  });
}

return orders.map((order) => {
  const base = {
    orderId: order.orderId,
    serviceType: order.serviceType,
    origin: order.origin,
    destination: order.destination,
    weightKg: order.weightKg,
    assignedDriver: $input.first().json.assigned_vehicle_id ,
  };

  if (order.serviceType === 'ltl') {
    const originProvince = getProvince(order.origin);
    const destinationProvince = getProvince(order.destination);

    const key = `${originProvince}__${destinationProvince}`;

    const plan = ltlPlans.get(key);

    return {
      ...base,
      vehicleType: plan?.vehicle.vehicleType || null,
      dispatchMode: plan?.vehicle.ready
        ? 'ltl_ready'
        : 'ltl_hold',
      ltlGroupKey: key,
      ltlTotalWeightKg:
        plan?.totalWeightKg ?? order.weightKg,
      ltlFillPercent:
        plan?.vehicle.fillPercent ?? 0,
      ltlMinFillRatio: MIN_FILL_RATIO,
    };
  }

  if (order.serviceType === 'ftl') {
    const vehicle = pickMinVehicle(order.weightKg);

    return {
      ...base,
      vehicleType: vehicle.vehicleType,
      dispatchMode: 'ftl_direct',
      ftlCapacityKg: vehicle.capacityKg,
    };
  }

  const vehicle = pickMinVehicle(order.weightKg);

  return {
    ...base,
    vehicleType: vehicle.vehicleType,
    dispatchMode: 'standard',
  };
});

// Choose vehicle based on service type + province rule + region proximity

const vehicles = $input.all().map((item) => item.json || {});

const orderSource =
  $items('classify')[0]?.json ||
  $items('Get order info')[0]?.json ||
  $json ||
  {};

const serviceType = String(
  orderSource.serviceType ||
  orderSource.service_type ||
  ''
).toLowerCase();

const toNum = (value, fallback = 0) => {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
};

const normalizeText = (value) =>
  String(value || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\./g, '')
    .trim();

const getProvince = (address) => {
  const parts = String(address || '')
    .split(',')
    .map((part) => part.trim())
    .filter(Boolean);

  return parts.length
    ? parts[parts.length - 1]
    : String(address || '').trim();
};

const originProvince = getProvince(
  orderSource.origin || ''
);

const destinationProvince = getProvince(
  orderSource.destination || ''
);

const sameProvince =
  normalizeText(originProvince) &&
  normalizeText(originProvince) ===
    normalizeText(destinationProvince);

const allowedTypes = sameProvince
  ? new Set([
      'motorbike',
      'van',
      'truck',
      'refrigerated_truck',
      'heavy_truck',
    ])
  : new Set([
      'van',
      'truck',
      'refrigerated_truck',
      'heavy_truck',
    ]);

const availableVehicles = vehicles.filter(
  (vehicle) => {
    const statusOk =
      String(vehicle.status || '').toLowerCase() ===
      'available';

    const typeOk = allowedTypes.has(
      String(vehicle.vehicle_type || '').toLowerCase()
    );

    return statusOk && typeOk;
  }
);

const originNorm = normalizeText(originProvince);

const regionMatched = availableVehicles.filter(
  (vehicle) => {
    const regionNorm = normalizeText(
      vehicle.region || ''
    );

    return (
      originNorm &&
      (
        regionNorm.includes(originNorm) ||
        originNorm.includes(regionNorm)
      )
    );
  }
);

const candidates = regionMatched.length
  ? regionMatched
  : availableVehicles;

const ltlWeight = toNum(
  orderSource.ltlTotalWeightKg ??
    orderSource.weightKg ??
    orderSource.weight ??
    orderSource.weight_kg,
  0
);

const ftlWeight = toNum(
  orderSource.weightKg ??
    orderSource.weight ??
    orderSource.weight_kg,
  0
);

function pickLtlVehicle(list, totalWeight) {
  const fitting = list.filter(
    (v) =>
      toNum(v.capacity_available, 0) >=
      totalWeight
  );

  if (fitting.length > 0) {
    const sorted = [...fitting].sort((a, b) => {
      const aRemain =
        toNum(a.capacity_available, 0) -
        totalWeight;

      const bRemain =
        toNum(b.capacity_available, 0) -
        totalWeight;

      return aRemain - bRemain;
    });

    return sorted[0];
  }

  return (
    [...list].sort(
      (a, b) =>
        toNum(b.capacity_available, 0) -
        toNum(a.capacity_available, 0)
    )[0] || null
  );
}

function pickFtlVehicle(list, weight) {
  const fitting = list.filter(
    (v) => toNum(v.capacity_kg, 0) >= weight
  );

  if (fitting.length > 0) {
    const sorted = [...fitting].sort(
      (a, b) =>
        toNum(a.capacity_kg, 0) -
        toNum(b.capacity_kg, 0)
    );

    return sorted[0];
  }

  return (
    [...list].sort(
      (a, b) =>
        toNum(b.capacity_kg, 0) -
        toNum(a.capacity_kg, 0)
    )[0] || null
  );
}

let selected = null;
let selectionReason = '';

if (serviceType === 'ltl') {
  selected = pickLtlVehicle(
    candidates,
    ltlWeight
  );

  selectionReason = selected
    ? `LTL best-fit capacity_available for ${ltlWeight} kg`
    : 'No available vehicle for LTL';

} else if (serviceType === 'ftl') {
  selected = pickFtlVehicle(
    candidates,
    ftlWeight
  );

  selectionReason = selected
    ? `FTL best-fit capacity_kg for ${ftlWeight} kg`
    : 'No available vehicle for FTL';

} else {
  selected = pickFtlVehicle(
    candidates,
    ftlWeight
  );

  selectionReason = selected
    ? `Standard best-fit capacity_kg for ${ftlWeight} kg`
    : 'No available vehicle';
}

return [
  {
    json: {
      ...orderSource,

      selectedVehicle: selected,

      assignedVehicleId:
        selected?.id || null,

      vehicleType:
        selected?.vehicle_type || null,

      plateNumber:
        selected?.plate_number || null,

      capacityRemaining:
        serviceType === 'ltl' && selected
          ? toNum(selected.capacity_available, 0) -
            ltlWeight
          : null,
      capacityFillPercent:
  serviceType === 'ltl' && selected
    ? Number(
        (
          (ltlWeight /
            toNum(selected.capacity_available, 1)) *
          100
        ).toFixed(1)
      )
    : null,

      selectionReason,

      sameProvince,
    },
  },
];

// Lấy raw output
const raw = $json.output || "{}";

// Parse JSON string
const data = JSON.parse(raw);

return [
  {
    json: {
      cargoType: data.cargoType || null,
      confidence: data.confidence || 0,
      handlingRequirements: data.handlingRequirements || "",
      reason: data.reason || "",
      vehicle_type: data.vehicle_type || "",
      licenses: data.licenses || ""
    }
  }
];

// Choose driver by origin proximity + vehicle type + availability

const drivers = $input.all().map((item) => item.json || {});

const orderSource =
  $items('choose vehicle')[0]?.json ||
  $items('classify')[0]?.json ||
  $items('Get order info')[0]?.json ||
  $json ||
  {};

const origin = String(orderSource.origin || '');

const vehicleType = String(
  orderSource.vehicleType ||
  orderSource.vehicle_type ||
  ''
).toLowerCase();

const assignedVehicleId =
  orderSource.assignedVehicleId ||
  orderSource.selectedVehicle?.id ||
  null;

const LICENSE_MAP = {
  motorbike: 'motorbike',
  van: 'van',
  truck: 'truck',
  refrigerated_truck: 'truck',
  heavy_truck: 'heavy_truck',
};

const requiredLicense =
  LICENSE_MAP[vehicleType] || 'motorbike';

const normalizeText = (value) =>
  String(value || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\./g, '')
    .trim();

const normalizeLicenses = (value) => {
  if (Array.isArray(value)) {
    return value.map((item) =>
      normalizeText(item)
    );
  }

  if (typeof value === 'string') {
    return value
      .split(/[\s,]+/)
      .map((item) => normalizeText(item))
      .filter(Boolean);
  }

  return [];
};

const originNorm = normalizeText(origin);

const availableDrivers = drivers.filter(
  (driver) =>
    String(driver.status || '').toLowerCase() ===
    'available'
);

const licensedDrivers = availableDrivers.filter(
  (driver) => {
    const licenses = normalizeLicenses(
      driver.licenses
    );

    return licenses.includes(requiredLicense);
  }
);

const scored = licensedDrivers.map((driver) => {
  const regionNorm = normalizeText(
    driver.region || ''
  );

  const regionMatch =
    originNorm &&
    (
      regionNorm.includes(originNorm) ||
      originNorm.includes(regionNorm)
    );

  const vehicleMatch =
    assignedVehicleId &&
    driver.vehicle_id === assignedVehicleId;

  const workload = Number(driver.workload ?? 0);

  const score =
    (vehicleMatch ? 50 : 0) +
    (regionMatch ? 10 : 0) -
    workload;

  return {
    driver,
    score,
    regionMatch,
    vehicleMatch,
    workload,
  };
});

scored.sort((a, b) => {
  if (b.score !== a.score) {
    return b.score - a.score;
  }

  return a.workload - b.workload;
});

const best = scored[0] || null;

const selected = best?.driver || null;

return [
  {
    json: {
      ...orderSource,

      assignedDriver: selected,

      assignedDriverId:
        selected?.id || null,

      assignedDriverName:
        selected?.name || null,

      assignedDriverRegion:
        selected?.region || null,

      driverSelectionReason: selected
        ? `Match: ${
            best?.regionMatch
              ? 'region'
              : 'license'
          }${
            best?.vehicleMatch
              ? ' + vehicle'
              : ''
          }`
        : 'No available driver',
    },
  },
];
